DROP TABLE IF EXISTS `caipiao_wanfa`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `caipiao_wanfa` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `title` varchar(60) NOT NULL,
  `typeid` char(30) NOT NULL,
  `playid` char(30) NOT NULL,
  `totalzs` int(11) NOT NULL COMMENT 'số cược',
  `maxjj` text NOT NULL COMMENT 'cao nhấttiền thưởng',
  `minjj` text NOT NULL COMMENT 'thấp nhấttiền thưởng',
  `maxrate` text NOT NULL COMMENT '//tối đatỷ lệ',
  `minrate` text NOT NULL COMMENT '//tối thiểutỷ lệ',
  `rate` text NOT NULL COMMENT 'tỷ lệ',
  `fandian` decimal(3,1) NOT NULL,
  `maxzs` int(6) NOT NULL DEFAULT '0' COMMENT 'cao nhấtsố cược',
  `minxf` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT 'thấp nhất',
  `maxxf` decimal(10,2) NOT NULL DEFAULT '10000.00' COMMENT 'tối đasố tiền đặt cược',
  `maxprize` decimal(12,2) NOT NULL,
  `remark` text NOT NULL,
  `isopen` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1bật 0tắt',
  PRIMARY KEY (`id`),
  KEY `typeid` (`typeid`),
  KEY `playid` (`playid`)
) ENGINE=InnoDB AUTO_INCREMENT=1283 DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC;
